import{_ as i,c as s,a,o as d}from"./app-CEcM0piI.js";const n={};function t(r,e){return d(),s("div",null,e[0]||(e[0]=[a(`<p>在标准C++没有提供专门用于套接字通信的类，所以只能使用操作系统提供的基于C的API函数，基于这些C的API函数我们也可以封装自己的C++类 <strong>需要导入network模块</strong></p><p>qt提供了用于套接字通信的类（TCP、UDP）</p><p>使用Qt提供的类进行基于TCP的套接字通信需要用到两个类： 这些类的父类和qt中的文件类QFile是一样的都是QIOdevice</p><ul><li>QTcpServer：服务器类，用于监听客户端连接以及和客户端建立连接。</li><li>QTcpSocket：通信的套接字类，客户端、服务器端都需要使用。</li></ul><p>这两个套接字通信类都属于网络模块<code>network</code>。</p><h1 id="qtcpserver" tabindex="-1"><a class="header-anchor" href="#qtcpserver"><span># QTcpServer</span></a></h1><p>用于监听客户端连接以及和客户端建立连接</p><h3 id="公共成员函数" tabindex="-1"><a class="header-anchor" href="#公共成员函数"><span>公共成员函数</span></a></h3><h4 id="构造函数" tabindex="-1"><a class="header-anchor" href="#构造函数"><span>构造函数</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QTcpServer::QTcpServer(QObject *parent = Q_NULLPTR);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="设置监听" tabindex="-1"><a class="header-anchor" href="#设置监听"><span>设置监听</span></a></h4><p><strong>绑定端口并设置监听</strong></p><ul><li>address：通过类<code>QHostAddress</code>可以封装<code>IPv4</code>、<code>IPv6</code>格式的IP地址， <code>QHostAddress::Any</code>表示自动绑定任意ip地址 <code>AnyIPv6</code>: 任意ipv6地址 <code>AnyIPv4</code>: 任意的ipv4地址 <code>Broadcast</code>: 广播地址 <code>LocalHostIPv6</code>: 本地的ipv6地址 <code>LocalHopst</code>: 本地的ip地址127.0.0.1 <code>Null</code>: 空地址</li><li>port：如果指定为0表示随机绑定一个可用端口。</li><li>返回值：绑定成功返回true，失败返回false</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>bool QTcpServer::listen(const QHostAddress &amp;address = QHostAddress::Any, quint16 port = 0);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>判断监听</strong></p><p>判断当前对象是否在监听, 是返回true，没有监听返回false</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>bool QTcpServer::isListening() const;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果当前对象正在监听返回监听的服务器地址信息, 否则返回 QHostAddress::Null</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QHostAddress QTcpServer::serverAddress() const;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果服务器正在侦听连接，则返回服务器的端口; 否则返回0</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>quint16 QTcpServer::serverPort() const</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="获取连接" tabindex="-1"><a class="header-anchor" href="#获取连接"><span>获取连接</span></a></h4><p>得到和客户端建立连接之后用于通信的<code>QTcpSocket</code>套接字对象 <code>QTcpSocket</code>是<code>QTcpServer</code>的一个子对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QTcpSocket *QTcpServer::nextPendingConnection();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>指向的是一块堆内存,<code>QTcpServer</code>对象析构的时候会自动析构这个子对象，也可自己手动析构，建议用完之后自己手动析构这个通信的<code>QTcpSocket</code>对象。</p><h4 id="" tabindex="-1"><a class="header-anchor" href="#"><span></span></a></h4><p>阻塞等待客户端发起的连接请求，不推荐在单线程程序中使用，建议使用非阻塞方式处理新连接，使用信号 <code>newConnection()</code> 。</p><ul><li>msec：指定阻塞的最大时长，单位为毫秒（ms）</li><li>timeout：传出参数，如果操作超时timeout为true，没有超时timeout为false</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>bool QTcpServer::waitForNewConnection(int msec = 0, bool *timedOut = Q_NULLPTR);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="信号槽" tabindex="-1"><a class="header-anchor" href="#信号槽"><span>信号槽</span></a></h3><p>socketError参数描述了发生的错误相关的信息。 当接受新连接导致错误时，将发射该信号。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[signal] void QTcpServer::acceptError(QAbstractSocket::SocketError socketError);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>每次有新连接可用时都会发出 newConnection() 信号。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[signal] void QTcpServer::newConnection();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="qtcpsocket" tabindex="-1"><a class="header-anchor" href="#qtcpsocket"><span>QTcpSocket</span></a></h1><h3 id="构造函数-1" tabindex="-1"><a class="header-anchor" href="#构造函数-1"><span>构造函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QTcpSocket::QTcpSocket(QObject *parent = Q_NULLPTR);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="连接服务器" tabindex="-1"><a class="header-anchor" href="#连接服务器"><span>连接服务器</span></a></h3><p>需要指定服务器端绑定的IP和端口信息。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[virtual] void QAbstractSocket::connectToHost(const QString &amp;hostName, quint16 port, OpenMode openMode = ReadWrite, NetworkLayerProtocol protocol = AnyIPProtocol);  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>[virtual] void QAbstractSocket::connectToHost(const QHostAddress &amp;address, quint16 port, OpenMode openMode = ReadWrite);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在Qt中不管调用读操作函数接收数据，还是调用写函数发送数据，操作的对象都是本地的由Qt框架维护的一块内存。因此，调用了发送函数数据不一定会马上被发送到网络中，调用了接收函数也不是直接从网络中接收数据</p><h4 id="接收数据" tabindex="-1"><a class="header-anchor" href="#接收数据"><span>接收数据</span></a></h4><p>指定可接收的最大字节数 maxSize 的数据到指针 data 指向的内存中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>qint64 QIODevice::read(char *data, qint64 maxSize);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>指定可接收的最大字节数 maxSize，返回接收的字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QByteArray QIODevice::read(qint64 maxSize);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将当前可用操作数据全部读出，通过返回值返回读出的字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QByteArray QIODevice::readAll();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="发送数据" tabindex="-1"><a class="header-anchor" href="#发送数据"><span>发送数据</span></a></h4><p>发送指针 data 指向的内存中的 maxSize 个字节的数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>qint64 QIODevice::write(const char *data, qint64 maxSize);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>发送指针 data 指向的内存中的数据，字符串以 \\0 作为结束标记</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>qint64 QIODevice::write(const char *data);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>发送参数指定的字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>qint64 QIODevice::write(const QByteArray &amp;byteArray);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="信号槽-1" tabindex="-1"><a class="header-anchor" href="#信号槽-1"><span>信号槽</span></a></h3><p>在使用<code>QTcpSocket</code>进行套接字通信的过程中，如果该类对象发射出<code>readyRead()</code>信号，说明对端发送的数据达到了，之后就可以调用 <code>read 函数</code>接收数据了。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[signal] void QIODevice::readyRead();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>调用<code>connectToHost()</code>函数并成功建立连接之后发出<code>connected()</code>信号。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[signal] void QAbstractSocket::connected();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在套接字断开连接时发出<code>disconnected()</code>信号。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[signal] void QAbstractSocket::disconnected();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="通信流程" tabindex="-1"><a class="header-anchor" href="#通信流程"><span>通信流程</span></a></h3><h4 id="服务器端" tabindex="-1"><a class="header-anchor" href="#服务器端"><span>服务器端</span></a></h4><ol><li>创建套接字服务器<code>QTcpServer</code>对象</li><li>通过<code>QTcpServer</code>对象设置监听，即：<code>QTcpServer::listen()</code></li><li>基于<code>QTcpServer::newConnection()</code>信号检测是否有新的客户端连接</li><li>如果有新的客户端连接调用<code>QTcpSocket *QTcpServer::nextPendingConnection()</code>得到通信的套接字对象</li><li>使用通信的套接字对象<code>QTcpSocket</code>和客户端进行通信</li></ol><h4 id="客户端" tabindex="-1"><a class="header-anchor" href="#客户端"><span>客户端</span></a></h4><ol><li>创建通信的套接字类<code>QTcpSocket</code>对象</li><li>使用服务器端绑定的IP和端口连接服务器<code>QAbstractSocket::connectToHost()</code></li><li>使用<code>QTcpSocket</code>对象和服务器进行通信</li></ol>`,67)]))}const c=i(n,[["render",t]]),h=JSON.parse('{"path":"/cpp/qt/6/","title":"6 QT套接字","lang":"zh-CN","frontmatter":{"title":"6 QT套接字","createTime":"2025/06/18 20:54:26","permalink":"/cpp/qt/6/"},"readingTime":{"minutes":4.24,"words":1271},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/Qt/6 QT套接字.md","headers":[]}');export{c as comp,h as data};
